#include <stdio.h>
#include <stdlib.h>
#define MAX 100005
#define INF 0x3f3f3f3f
typedef struct Edge { int u, v, w; } Edge;
int compare(const void *a, const void *b) { return ((Edge *)a)->w - ((Edge *)b)->w; }
int find(int *fa, int x) { return fa[x] == x ? x : fa[x] = find(fa, fa[x]); }
int kruskal(Edge *e, int n, int m) { int fa[n + 1], ans = 0, cnt = 0; for (int i = 1; i <= n; i++) fa[i] = i; qsort(e, m, sizeof(Edge), compare); for (int i = 0; i < m; i++) { int fu = find(fa, e[i].u), fv = find(fa, e[i].v); if (fu != fv) { fa[fu] = fv; ans += e[i].w; cnt++; } if (cnt == n - 1) break; } return ans; }
int main() { int n, m; scanf("%d %d", &n, &m); Edge e[m]; for (int i = 0; i < m; i++) scanf("%d %d %d", &e[i].u, &e[i].v, &e[i].w); for (int i = 0; i < m; i++) { Edge tmp[m - 1]; int j = 0; for (int k = 0; k < m; k++) if (k != i) tmp[j++] = e[k]; printf("%d\n", kruskal(tmp, n, m - 1)); } return 0; }

