import java.util.Arrays;
import java.util.Scanner;
public class Main { public static void main(String[] args) { Scanner sc = new Scanner(System.in); int n = sc.nextInt(), m = sc.nextInt(); Edge[] e = new Edge[m]; for (int i = 0; i < m; i++) { e[i] = new Edge(sc.nextInt(), sc.nextInt(), sc.nextInt()); } for (int i = 0; i < m; i++) { Edge[] tmp = new Edge[m - 1]; int j = 0; for (int k = 0; k < m; k++) if (k != i) tmp[j++] = e[k]; System.out.println(kruskal(tmp, n)); } }
public static int kruskal(Edge[] e, int n) { int[] fa = new int[n + 1]; int ans = 0, cnt = 0; for (int i = 1; i <= n; i++) fa[i] = i; Arrays.sort(e, (a, b) -> a.w - b.w); for (int i = 0; i < e.length; i++) { int fu = find(fa, e[i].u), fv = find(fa, e[i].v); if (fu != fv) { fa[fu] = fv; ans += e[i].w; cnt++; } if (cnt == n - 1) break; } return ans; }
public static int find(int[] fa, int x) { return fa[x] == x ? x : (fa[x] = find(fa, fa[x])); }
static class Edge { int u, v, w; Edge(int u, int v, int w) { this.u = u; this.v = v; this.w = w; } } }

