const readline = require('readline');
const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
let input = [];
rl.on('line', line => input.push(line));
rl.on('close', () => {
    let [n, m] = input[0].split(' ').map(Number);
    let e = input.slice(1).map(line => line.split(' ').map(Number));
    function find(fa, x) { return fa[x] === x ? x : (fa[x] = find(fa, fa[x])); }
    function kruskal(e, n) {
        let fa = Array(n + 1).fill(0).map((_, i) => i);
        let ans = 0, cnt = 0;
        e.sort((a, b) => a[2] - b[2]);
        for (let [u, v, w] of e) {
            let fu = find(fa, u), fv = find(fa, v);
            if (fu !== fv) {
                fa[fu] = fv;
                ans += w;
                cnt++;
            }
            if (cnt === n - 1) break;
        }
        return ans;
    }
    for (let i = 0; i < m; i++) {
        let tmp = e.slice(0, i).concat(e.slice(i + 1));
        console.log(kruskal(tmp, n));
    }
});
